sql:
SELECT DISTINCT major_name
FROM majors
WHERE major_category = 0;

SELECT m.major_name, es.grad_unemployment_rate
FROM majors m
JOIN employment_statistics es ON m.major_code = es.major_code
WHERE es.grad_unemployment_rate = (
    SELECT MAX(grad_unemployment_rate) FROM employment_statistics
);

SELECT geographic_location, grad_full_time_year_round
FROM employment_statistics
WHERE grad_full_time_year_round > (SELECT AVG(grad_full_time_year_round) FROM employment_statistics);

SELECT value 
FROM report_filters 
WHERE filter_id = 0;

SELECT approval_status, COUNT(version_id) AS Total_Versions
FROM data_versions
GROUP BY approval_status;

external_knowledge:
- 'Key categories' refer to major categories with codes 1, 2, and 3;
- 'Highest struggle in the job market' refers to higher unemployment rates among graduates;
- The data is from the year 2020 and for graduates and non-graduates in New York.

